const crypto = require('crypto');
const headers = $input.first().json.headers || {};
const raw = $input.first().json.body;
const rawString = typeof raw === 'string' ? raw : JSON.stringify(raw);
const secret = $env.PAYMENT_GATEWAY_SECRET || '';
const sigHeader = headers['x-signature'] || headers['x-callback-signature'] || '';
const expected = secret ? crypto.createHmac('sha256', secret).update(rawString).digest('hex') : '';
const valid = !secret || sigHeader === expected;
let body = raw;
if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) { body = {}; } }
return [{ json: {
  valid,
  ref: body.reference || body.booking_ref,
  status: (body.status || '').toUpperCase(),
  txn_ref: body.transaction_id || body.txn_ref,
  amount: body.amount,
  provider: body.provider,
  reason: body.failure_reason || body.message || null,
  raw: body
} }];

const r = $input.first().json;
if (!r || !r.ref) return [{ json: { skip: true } }];
const dep = new Date(r.departure_at);
const dateStr = dep.toLocaleDateString('sw-TZ');
const hh = String(dep.getHours()).padStart(2,'0');
const mm = String(dep.getMinutes()).padStart(2,'0');
const sms = `Bus TZ PAWA — Tiketi yako: ${r.ref}\nJina: ${r.passenger_name}\nSafari: ${r.origin} -> ${r.destination}\nTarehe: ${dateStr} saa ${hh}:${mm}\nKiti: ${r.seat_number}\nBasi: ${r.plate || 'TBD'} (${r.class || 'standard'})\nMalipo: TZS ${Number(r.amount).toLocaleString()} - YAMEKAMILIKA\nFika eneo la kupanda dakika 30 kabla. Safari njema!`;
return [{ json: { phone: r.phone, message: sms, ref: r.ref } }];

const b = $('DB Confirm Booking').first().json;
if (!b || !b.ref) return [{ json: { skip: true } }];

const amount = Number(b.amount);
const dep = new Date(b.departure_at);
const dateStr = dep.toLocaleDateString('sw-TZ');
const hh = String(dep.getHours()).padStart(2,'0');
const mm = String(dep.getMinutes()).padStart(2,'0');
const paidAt = new Date().toLocaleString('en-TZ', { timeZone: 'Africa/Dar_es_Salaam' });

const email_html = `<!DOCTYPE html>
<html><body style="font-family:sans-serif;max-width:600px;margin:0 auto;">
<h2 style="color:#1a5c2a;">BUS TZ PAWA — New Payment Received</h2>
<table border="1" cellpadding="10" cellspacing="0" style="border-collapse:collapse;width:100%;">
  <tr style="background:#f0f0f0;"><td><strong>Booking Ref</strong></td><td>${b.ref}</td></tr>
  <tr><td><strong>Passenger</strong></td><td>${b.passenger_name}</td></tr>
  <tr style="background:#f0f0f0;"><td><strong>Phone</strong></td><td>${b.phone}</td></tr>
  <tr><td><strong>Route</strong></td><td>${b.origin} &rarr; ${b.destination}</td></tr>
  <tr style="background:#f0f0f0;"><td><strong>Departure</strong></td><td>${dateStr} ${hh}:${mm}</td></tr>
  <tr><td><strong>Seat</strong></td><td>${b.seat_number}</td></tr>
  <tr style="background:#f0f0f0;"><td><strong>Bus</strong></td><td>${b.plate || 'TBD'} (${b.class || 'standard'})</td></tr>
  <tr style="background:#d4edda;"><td><strong>Total Amount Paid</strong></td><td><strong style="font-size:1.2em;">TZS ${amount.toLocaleString()}</strong></td></tr>
  <tr><td><strong>Paid At</strong></td><td>${paidAt}</td></tr>
</table>
<p style="color:#1a5c2a;font-weight:bold;">Payment confirmed successfully.</p>
</body></html>`;

return [{
  json: {
    ref: b.ref,
    total_amount: amount,
    total_amount_formatted: `TZS ${amount.toLocaleString()}`,
    email_subject: `[BUS TZ PAWA] Payment Confirmed: ${b.ref} — TZS ${amount.toLocaleString()}`,
    email_html
  }
}];
